#include "interface.h"

uint64_t packed12_filter_sum(const std::vector<uint8_t>& packed, uint16_t threshold, int iters) {
  const uint32_t t = static_cast<uint32_t>(threshold);
  const std::size_t packed_len = packed.size();
  const uint8_t* data = packed.data();
  uint64_t sum = 0;

  for (int iter = 0; iter < iters; ++iter) {
    sum = 0;
    for (std::size_t i = 0; i < packed_len; i += 3) {
      const uint32_t a = static_cast<uint32_t>(data[i]) | 
                          (static_cast<uint32_t>(data[i+1] & 0x0FU) << 8U);
      const uint32_t b = (static_cast<uint32_t>(data[i+1] >> 4U)) | 
                          (static_cast<uint32_t>(data[i+2]) << 4U);
      if (a > t) sum += a;
      if (b > t) sum += b;
    }
  }
  return sum;
}
